// Web Worker 入口點 - 無 Vue / DOM 依賴
import { PureActorManager, PureDamageCollectorManager } from "./pureEventActor";
import type {
    WorkerInMessage,
    WorkerOutMessage,
    WorkerSnapshot,
    SnapshotEntity,
    SnapshotGroup,
} from "./workerProtocol";

self.onmessage = (e: MessageEvent<WorkerInMessage>) => {
    if (e.data.type !== "process") return;

    try {
        const snapshot = process(e.data.ndjson);
        const msg: WorkerOutMessage = { type: "done", snapshot };
        self.postMessage(msg);
    } catch (err) {
        const msg: WorkerOutMessage = { type: "error", message: String(err) };
        self.postMessage(msg);
    }
};

function process(ndjson: string): WorkerSnapshot {
    const dcMgr = new PureDamageCollectorManager();
    const actorMgr = new PureActorManager(dcMgr);

    // ── Phase 1: JSON parse ────────────────────────────────────────────────
    const events: any[] = [];
    let lastPos = 0;
    const total = ndjson.length;
    let lastReportedPct = -1;

    while (lastPos < total) {
        const nextPos = ndjson.indexOf("\n", lastPos);
        if (nextPos < 0) break;

        const line = ndjson.substring(lastPos, nextPos).trim();
        lastPos = nextPos + 1;

        if (!line) continue;

        try {
            events.push(JSON.parse(line));
        } catch {
            continue;
        }

        // 每 2% 回報一次進度，避免訊息風暴
        const pct = Math.floor((lastPos / total) * 50);
        if (pct > lastReportedPct) {
            lastReportedPct = pct;
            const msg: WorkerOutMessage = {
                type: "progress",
                pct,
                phase: "parse",
            };
            self.postMessage(msg);
        }
    }

    // ── Phase 2: onEvent 處理 ──────────────────────────────────────────────
    const eventCount = events.length;
    lastReportedPct = 49;

    for (let i = 0; i < eventCount; i++) {
        actorMgr.onEvent(events[i]);

        const pct = 50 + Math.floor((i / eventCount) * 50);
        if (pct > lastReportedPct) {
            lastReportedPct = pct;
            const msg: WorkerOutMessage = {
                type: "progress",
                pct,
                phase: "process",
            };
            self.postMessage(msg);
        }
    }

    // ── Phase 3: 建立 snapshot ─────────────────────────────────────────────
    const entities: Record<string, SnapshotEntity> = {};
    for (const [id, e] of Object.entries(actorMgr.entityMap)) {
        entities[id] = {
            id: e.id,
            raceId: e.raceId,
            name: e.name,
            guildName: e.guildName,
            ownerId: e.ownerId,
            finisherId: e.finisherId,
            body: { ...e.body },
            totalTakeDamage: e.totalTakeDamage,
            takeDamages: e.takeDamages,
            totalApplyDamage: e.totalApplyDamage,
            applyDamages: e.applyDamages,
            conditionMap: { ...e.conditionMap },
            conditionHistory: e.conditionHistory,
            equipItemMap: { ...e.equipItemMap },
            groupKey: PureActorManager.groupTargetKey({
                Id: id,
                RaceId: e.raceId,
            } as any),
        };
    }

    const groups: Record<string, SnapshotGroup> = {};
    for (const [key, g] of Object.entries(actorMgr.groupMap)) {
        groups[key] = {
            id: g.id,
            raceId: g.raceId,
            name: g.name,
            body: { ...g.body },
            totalTakeDamage: g.totalTakeDamage,
            takeDamages: g.takeDamages,
        };
    }

    return {
        entities,
        groups,
        damages: actorMgr.damages,
        collectorDamages: dcMgr.damages,
    };
}
